import{_ as e,c as a,o,d as i}from"./app.617a6e1c.js";const b=JSON.parse('{"title":"Due\xF1o del Producto (Product Owner)","description":"","frontmatter":{},"headers":[{"level":2,"title":"El Due\xF1o del Producto es quien","slug":"el-dueno-del-producto-es-quien","link":"#el-dueno-del-producto-es-quien","children":[]},{"level":2,"title":"Funciones y responsabilidades","slug":"funciones-y-responsabilidades","link":"#funciones-y-responsabilidades","children":[]},{"level":2,"title":"Para ejercer este rol es necesario","slug":"para-ejercer-este-rol-es-necesario","link":"#para-ejercer-este-rol-es-necesario","children":[]},{"level":2,"title":"Aptitudes que debe tener","slug":"aptitudes-que-debe-tener","link":"#aptitudes-que-debe-tener","children":[]},{"level":2,"title":"Es adem\xE1s recomendable que el propietario de producto:","slug":"es-ademas-recomendable-que-el-propietario-de-producto","link":"#es-ademas-recomendable-que-el-propietario-de-producto","children":[]}],"relativePath":"roles/product-owner.md"}'),r={name:"roles/product-owner.md"},n=i('<h1 id="dueno-del-producto-product-owner" tabindex="-1">Due\xF1o del Producto <em>(Product Owner)</em> <a class="header-anchor" href="#dueno-del-producto-product-owner" aria-hidden="true">#</a></h1><p>El propietario de producto es la \xFAnica persona autorizada para decidir sobre cu\xE1les funcionalidades tendr\xE1 el producto. Es quien representa al usuario principal, dem\xE1s usuarios del software y todas aquellas partes interesadas en el producto. Es quien toma las decisiones del usuario. Su responsabilidad es el valor del producto.</p><p>Para simplificar la comunicaci\xF3n y toma de decisiones es necesario que este rol recaiga en una \xFAnica persona. Si el usuario es una organizaci\xF3n grande, o con varios departamentos, puede adoptar la forma de comunicaci\xF3n interna que consideren oportuna, pero en el Equipo de Desarrollo s\xF3lo se integra una persona en representaci\xF3n del usuario, y \xE9sta debe tener el conocimiento suficiente del producto y las atribuciones necesarias para tomar las decisiones que le corresponden.</p><h2 id="el-dueno-del-producto-es-quien" tabindex="-1">El Due\xF1o del Producto es quien <a class="header-anchor" href="#el-dueno-del-producto-es-quien" aria-hidden="true">#</a></h2><ul><li><p>Decide en \xFAltima instancia c\xF3mo ser\xE1 el resultado final, y el orden en el que se van construyendo los sucesivos incrementos: qu\xE9 se pone y qu\xE9 se quita de la Pila del Producto, y cu\xE1l es la prioridad de las funcionalidades.</p></li><li><p>Conoce el plan del producto y sus posibilidades, as\xED como del retorno esperado a la inversi\xF3n realizada, y se responsabiliza sobre fechas y funcionalidades de las diferentes versiones del mismo.</p></li></ul><h2 id="funciones-y-responsabilidades" tabindex="-1">Funciones y responsabilidades <a class="header-anchor" href="#funciones-y-responsabilidades" aria-hidden="true">#</a></h2><ul><li>Canalizar las necesidades del negocio, sabiendo &quot;escuchar&quot; a las partes interesadas en el producto y transmitirlas en &quot;objetivos de valor para el producto&quot;, al Equipo de Desarrollo.</li><li>Revisar el producto e ir adapt\xE1ndole sus funcionalidades, analizando las mejoras que \xE9stas puedan otorgar mayor valor para el negocio.</li><li>Maximizar el valor para el negocio con respecto al retorno de inversi\xF3n, abogando por los intereses del negocio.</li></ul><h2 id="para-ejercer-este-rol-es-necesario" tabindex="-1">Para ejercer este rol es necesario <a class="header-anchor" href="#para-ejercer-este-rol-es-necesario" aria-hidden="true">#</a></h2><ul><li>Conocer perfectamente el entorno de negocio, las necesidades y el objetivo que se persigue con el sistema que se est\xE1 construyendo.</li><li>Tener la visi\xF3n del producto, as\xED como las necesidades concretas del proyecto, para poder priorizar eficientemente el trabajo.</li><li>Disponer de atribuciones y conocimiento del plan del producto suficiente para tomar las decisiones necesarias durante el proyecto, incluidas para cubrir las expectativas previstas.</li><li>Recibir y analizar de forma continua (retroalimentaci\xF3n) informaci\xF3n del entorno del negocio (evoluci\xF3n del mercado, competencia, alternativas) y del proyecto (sugerencias del equipo, alternativas t\xE9cnicas, pruebas y evaluaci\xF3n de cada incremento).</li></ul><h2 id="aptitudes-que-debe-tener" tabindex="-1">Aptitudes que debe tener <a class="header-anchor" href="#aptitudes-que-debe-tener" aria-hidden="true">#</a></h2><ul><li>Excelente facilidad de comunicaci\xF3n en las relaciones interpersonales.</li><li>Excelente conocimiento del negocio.</li><li>Facilidad para an\xE1lisis de relaciones costo/beneficio.</li><li>Visi\xF3n de negocios.</li></ul><h2 id="es-ademas-recomendable-que-el-propietario-de-producto" tabindex="-1">Es adem\xE1s recomendable que el propietario de producto: <a class="header-anchor" href="#es-ademas-recomendable-que-el-propietario-de-producto" aria-hidden="true">#</a></h2><ul><li>Conozca y haya trabajado previamente con el mismo equipo.</li><li>Conozca Scrum, para realizar con solvencia las tareas que le corresponden:</li><li>Elaboraci\xF3n y administraci\xF3n de la Pila del Producto. <ul><li>Exposici\xF3n de la visi\xF3n e Historias de Usuario, y participaci\xF3n en la</li><li>Reuni\xF3n de Planificaci\xF3n de cada Sprint.</li></ul></li></ul><p>La organizaci\xF3n debe respetar sus decisiones y no modificar prioridades ni elementos de la Pila del Producto.</p>',14),s=[n];function l(d,c,t,u,p,m){return o(),a("div",null,s)}const q=e(r,[["render",l]]);export{b as __pageData,q as default};
